public static long solve(long[][] grid, long k) {
    int m = grid.length;
    if (m == 0) {
        return 0;
    }
    int n = grid[0].length;
    boolean[][] visited = new boolean[m][n];
    long count = 0;

    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (grid[i][j] != 0 && !visited[i][j]) {
                long total = dfs(grid, visited, i, j, m, n);
                if (total % k == 0) {
                    count++;
                }
            }
        }
    }
    return count;
}

private static long dfs(long[][] grid, boolean[][] visited, int i, int j, int m, int n) {
    if (i < 0 || i >= m || j < 0 || j >= n || grid[i][j] == 0 || visited[i][j]) {
        return 0;
    }
    visited[i][j] = true;
    long total = grid[i][j];
    total += dfs(grid, visited, i + 1, j, m, n);
    total += dfs(grid, visited, i - 1, j, m, n);
    total += dfs(grid, visited, i, j + 1, m, n);
    total += dfs(grid, visited, i, j - 1, m, n);
    return total;
}
